	@Test
	void filterValuesAnchorPreservesBagResultsForInWithDuplicateConstants() {
		IRI med1000 = VF.createIRI("urn:med:1000");
		IRI med1001 = VF.createIRI("urn:med:1001");
		IRI med1002 = VF.createIRI("urn:med:1002");
		BindingSetAssignment input = values("drug", med1000, med1000, med1001, med1002);
		Filter original = new Filter(input, listMember("drug", med1000, med1000, med1001));

		TupleExpr rewritten = RuleCompiler.compile(StandardRuleSpecs.filterValuesAnchor())
				.apply(expr(original), null, null)
				.get(0)
				.alternative();

		assertEquals(multiset(eval(original)), multiset(eval(rewritten)));
	}

